Method.Source:
/// <summary>
/// this method updates other field on modification of one field.
/// </summary>
/// <param name = "_fieldId"></param>
public void modifiedField(FieldId _fieldId)
{
    next modifiedField (_fieldId);

    switch (_fieldId)
    {
        case fieldNum(ITMContainerActivityTable, ActualEndDate):

            if(ITMParameters::find().ETGEnableLandedCostOutboundOrder == NoYes::Yes)
            {
                ITMLine itmLineLoc, itmLineCheckLastLine;
                ITMContainerActivityTable containerActivityTable;

                select firstonly RecId from containerActivityTable order by RecId desc
                    where containerActivityTable.ShipId == this.ShipId
                    && containerActivityTable.ShipContainerId == this.ShipContainerId;

                if(containerActivityTable.RecId == this.RecId)
                {
                    ttsbegin;

                        update_recordset itmLineLoc
                        setting ETGGateInDate = this.ActualEndDate
                        where itmLineLoc.ShipId == this.ShipId
                            && itmLineLoc.ShipContainerId == this.ShipContainerId;

                    ttscommit;
                }
            }
            break;
    }
}
